### Meta Tags with next/head

```jsx
import Head from 'next/head';

export default function Page() {
  return (
    <>
      <Head>
        <title>My Page Title | Site</title>
        <meta name="description" content="A brief description of the page" />
        <meta name="keywords" content="nextjs, react, seo" />
        <meta name="robots" content="index, follow" />
      </Head>
      <h1>Page Content</h1>
    </>
  );
}
```

### Open Graph

Optimize for social sharing:

```jsx
import Head from 'next/head';

export default function BlogPost({ post }) {
  return (
    <Head>
      <title>{post.title} | Blog</title>
      <meta name="description" content={post.excerpt} />

      {/* Open Graph / Facebook */}
      <meta property="og:type" content="article" />
      <meta property="og:title" content={post.title} />
      <meta property="og:description" content={post.excerpt} />
      <meta property="og:image" content={post.ogImage} />
      <meta property="og:url" content={`https://mysite.com/blog/${post.slug}`} />

      {/* Twitter */}
      <meta name="twitter:card" content="summary_large_image" />
      <meta name="twitter:title" content={post.title} />
      <meta name="twitter:description" content={post.excerpt} />
      <meta name="twitter:image" content={post.ogImage} />
    </Head>
  );
}
```

### Sitemap Generation

Create `pages/sitemap.xml.js`:

```jsx
const EXTERNAL_DATA_URL = 'https://jsonplaceholder.typicode.com/posts';

function generateSiteMap(posts) {
  return `<?xml version="1.0" encoding="UTF-8"?>
    <urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">
      <url><loc>https://mysite.com</loc></url>
      <url><loc>https://mysite.com/about</loc></url>
      <url><loc>https://mysite.com/blog</loc></url>
      ${posts.map(({ id }) => `
        <url>
          <loc>https://mysite.com/blog/${id}</loc>
          <lastmod>${new Date().toISOString()}</lastmod>
          <changefreq>weekly</changefreq>
          <priority>0.7</priority>
        </url>
      `).join('')}
    </urlset>
  `;
}

export async function getServerSideProps({ res }) {
  const posts = await fetch(EXTERNAL_DATA_URL).then(r => r.json());

  res.setHeader('Content-Type', 'text/xml');
  res.write(generateSiteMap(posts));
  res.end();

  return { props: {} };
}

export default function SiteMap() {}
```

### Robots.txt

Create `public/robots.txt`:
```
User-agent: *
Allow: /
Sitemap: https://mysite.com/sitemap.xml
```

### Structured Data (JSON-LD)

```jsx
import Head from 'next/head';

export default function Article({ post }) {
  const structuredData = {
    '@context': 'https://schema.org',
    '@type': 'Article',
    headline: post.title,
    description: post.excerpt,
    author: { '@type': 'Person', name: post.author },
    datePublished: post.date,
  };

  return (
    <Head>
      <script
        type="application/ld+json"
        dangerouslySetInnerHTML={{ __html: JSON.stringify(structuredData) }}
      />
    </Head>
  );
}
```

### Canonical URLs

Prevent duplicate content:

```jsx
<Head>
  <link rel="canonical" href={`https://mysite.com/blog/${post.slug}`} />
</Head>
```

codeExample:
// components/SEO.js — reusable SEO component
export default function SEO({ title, description, image, url }) {
  const siteName = 'MySite';

  return (
    <Head>
      <title>{title} | {siteName}</title>
      <meta name="description" content={description} />
      <meta property="og:title" content={title} />
      <meta property="og:description" content={description} />
      <meta property="og:image" content={image} />
      <meta property="og:url" content={url} />
      <meta property="og:type" content="website" />
      <meta name="twitter:card" content="summary_large_image" />
      <meta name="twitter:title" content={title} />
      <meta name="twitter:description" content={description} />
      <meta name="twitter:image" content={image} />
      <link rel="canonical" href={url} />
    </Head>
  );
}
